import{_ as e,o as t,c as o,ag as s}from"./chunks/framework.BbyMWZAR.js";const g=JSON.parse('{"title":"cluster、worker_threads 与多进程","description":"","frontmatter":{"title":"cluster、worker_threads 与多进程","difficulty":"hard","tags":["cluster","worker_threads","多进程","多线程"],"estimate":30},"headers":[],"relativePath":"domains/nodejs/qa/qa-08-cluster-worker-threads.md","filePath":"domains/nodejs/qa/qa-08-cluster-worker-threads.md","lastUpdated":1783504823000}'),a={name:"domains/nodejs/qa/qa-08-cluster-worker-threads.md"};function d(l,r,n,i,c,h){return t(),o("div",null,[...r[0]||(r[0]=[s('<h1 id="问答-08-高级-cluster、worker-threads-与多进程" tabindex="-1">问答 08（高级）：cluster、worker_threads 与多进程 <a class="header-anchor" href="#问答-08-高级-cluster、worker-threads-与多进程" aria-label="Permalink to &quot;问答 08（高级）：cluster、worker_threads 与多进程&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>Node.js 如何利用多核 CPU？<code>child_process</code>、<code>cluster</code>、<code>worker_threads</code> 有什么区别和适用场景？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>背景</strong></p><ul><li>Node 主线程单线程执行 JS，默认只用一个核。要利用多核需借助多进程或多线程。</li></ul><p><strong>三种方案</strong></p><ol><li><strong>child_process</strong>：创建子进程（<code>spawn</code>/<code>exec</code>/<code>fork</code>）。<code>fork</code> 专门用于创建 Node 子进程并通过 IPC 通信。适合执行外部命令或独立 Node 脚本。</li><li><strong>cluster</strong>：基于 <code>child_process.fork</code>，多个 worker 进程<strong>共享同一个监听端口</strong>（由 master 分发连接），用于横向扩展 HTTP 服务器，充分利用多核。每个 worker 是独立进程、独立内存。</li><li><strong>worker_threads</strong>：<strong>线程</strong>级并行，同一进程内多线程，可通过 <code>SharedArrayBuffer</code>、<code>MessageChannel</code> 共享/传递数据。适合 <strong>CPU 密集型任务</strong>（计算），线程比进程更轻量、通信更快。</li></ol><p><strong>对比</strong></p><table tabindex="0"><thead><tr><th></th><th>隔离级别</th><th>内存</th><th>通信</th><th>适用</th></tr></thead><tbody><tr><td>child_process</td><td>进程</td><td>独立</td><td>IPC/管道</td><td>跑外部程序/脚本</td></tr><tr><td>cluster</td><td>进程</td><td>独立</td><td>IPC</td><td>扩展网络服务，多核吞吐</td></tr><tr><td>worker_threads</td><td>线程</td><td>可共享</td><td>MessagePort/SharedArrayBuffer</td><td>CPU 密集计算</td></tr></tbody></table><p><strong>选择</strong></p><ul><li>扩展 HTTP 吞吐 → cluster（或直接用 PM2 cluster 模式 / 容器多副本）。</li><li>大量计算不阻塞主线程 → worker_threads。</li><li>调用系统命令 → child_process。</li></ul><h2 id="追问-1-cluster-模式下多个-worker-如何共享端口-连接是怎么分发的" tabindex="-1">追问 1：cluster 模式下多个 worker 如何共享端口？连接是怎么分发的？ <a class="header-anchor" href="#追问-1-cluster-模式下多个-worker-如何共享端口-连接是怎么分发的" aria-label="Permalink to &quot;追问 1：cluster 模式下多个 worker 如何共享端口？连接是怎么分发的？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>master 进程创建监听 socket，worker 通过 IPC 从 master 获取连接。默认在多数平台使用 <strong>round-robin（轮询）</strong> 调度（<code>SCHED_RR</code>），由 master 决定把新连接交给哪个 worker（Windows 默认是让内核分发）。</li><li>因此对外只暴露一个端口，内部由多个进程处理，达到负载均衡与多核利用。</li><li>注意 worker 之间不共享内存，session/缓存需外置（Redis），否则会不一致。</li></ul><h2 id="追问-2-worker-threads-之间如何高效传递大数据-postmessage-是拷贝还是共享" tabindex="-1">追问 2：worker_threads 之间如何高效传递大数据？<code>postMessage</code> 是拷贝还是共享？ <a class="header-anchor" href="#追问-2-worker-threads-之间如何高效传递大数据-postmessage-是拷贝还是共享" aria-label="Permalink to &quot;追问 2：worker_threads 之间如何高效传递大数据？`postMessage` 是拷贝还是共享？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><code>postMessage</code> 默认走<strong>结构化克隆（拷贝）</strong>，大数据拷贝开销大。</li><li>优化： <ol><li><strong>Transferable</strong>：传 <code>ArrayBuffer</code> 时可放进 transfer list，转移所有权（零拷贝），但原线程之后不能再用它。</li><li><strong>SharedArrayBuffer</strong>：真正的共享内存，多线程可同时读写，配合 <code>Atomics</code> 做同步，避免拷贝，适合大数组/高频交换。</li></ol></li><li>传递普通对象仍是克隆，注意成本。</li></ul><h2 id="追问-3-cluster-和-pm2-容器多副本-生产上怎么选" tabindex="-1">追问 3：cluster 和 PM2/容器多副本，生产上怎么选？ <a class="header-anchor" href="#追问-3-cluster-和-pm2-容器多副本-生产上怎么选" aria-label="Permalink to &quot;追问 3：cluster 和 PM2/容器多副本，生产上怎么选？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>cluster（应用内）</strong>：单机内多核利用，代码耦合，crash 处理和优雅退出要自己写。</li><li><strong>PM2 cluster 模式</strong>：帮你管理 worker 数量、自动重启、日志、零停机 reload，省去手写 master 逻辑。</li><li><strong>容器 + 多副本（k8s）</strong>：每个容器跑单进程 Node，由编排系统做扩缩容、健康检查、滚动更新，隔离性和可观测性最好，是云原生主流方案。</li><li>建议：云原生环境下常「单容器单进程 + 多副本」，把并发和多核交给编排层；单机部署可用 PM2 cluster。三者可组合。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/nodejs/RESOURCES">Node.js 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://nodejs.org/api/worker_threads.html" target="_blank" rel="noreferrer">Node.js: Worker Threads</a>：线程池、SharedArrayBuffer 与 CPU 密集任务隔离。</li><li><a href="https://nodejs.org/api/cluster.html" target="_blank" rel="noreferrer">Node.js: Cluster</a>：多进程共享端口与连接分发，扩展 HTTP 吞吐。</li><li><a href="https://docs.libuv.org/en/latest/design.html" target="_blank" rel="noreferrer">libuv Design Overview</a>：线程池默认大小与 CPU 密集 vs I/O 密集的底层分工。</li></ul>',24)])])}const k=e(a,[["render",d]]);export{g as __pageData,k as default};
